import hash from 'object-hash';
import { v4 as uuidv4 } from 'uuid';
import { mapPath } from './mapPath.js';
export const mapCallback = ({ callback, refUuidMap, uuidObjectHashMap, hashedNodeMap, uuid, }) => {
    // hash the raw object
    const objectHash = hash(callback);
    // map uuid and hash to uuidObjectHashMap
    uuidObjectHashMap[uuid] = objectHash;
    // if we've seen this exact object before, skip processing
    if (objectHash in hashedNodeMap) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        callback = objectHash;
        return;
    }
    // if ref, replace with uuid
    if ('$ref' in callback && callback.$ref) {
        const refId = callback.$ref;
        const refUuid = refUuidMap[refId];
        if (refUuid && uuidObjectHashMap[refUuid]) {
            uuidObjectHashMap[uuid] = uuidObjectHashMap[refUuid];
            return;
        }
        const resolvedRefUuid = refUuid || uuidv4();
        callback.$ref = resolvedRefUuid;
        hashedNodeMap[objectHash] = callback;
        return;
    }
    // for path item in callback, create Path node
    Object.entries(callback).forEach(([expression, pathItem]) => {
        const pathUuid = uuidv4();
        mapPath({
            pathItem: pathItem,
            refUuidMap,
            uuidObjectHashMap,
            hashedNodeMap,
            uuid: pathUuid,
            path: expression,
        });
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        callback[expression] = pathUuid;
    });
    // add to hashedNodeMap
    hashedNodeMap[objectHash] = callback;
};
